217→// Tests
218→// ---------------------------------------------------------------------------
219→
220→#[cfg(test)]
221→mod tests {
222→    use super::*;
223→    use crate::behavior::{Behavior, BehaviorMap};
224→    use crate::execution_record::ErrorInfo;
225→    use serde_json::json;
226→
227→    fn make_behavior(
228→        id: u32,
229→        inputs: Vec<serde_json::Value>,
230→        return_value: Option<serde_json::Value>,
231→        error: Option<ErrorInfo>,
232→    ) -> Behavior {
233→        Behavior {
234→            id,
235→            input_args: inputs,
236→            return_value,
237→            thrown_error: error,
238→            branch_path: vec![],
239→            side_effects: vec![],
240→            dependency_trace: None,
241→            mock_values: vec![],
242→        }
243→    }
244→
245→    fn make_behavior_map(function_id: &str, behaviors: Vec<Behavior>) -> BehaviorMap {
246→        BehaviorMap {
247→            function_id: function_id.to_string(),
248→            behaviors,
249→            fingerprint: None,
250→            nondeterministic_fields: vec![],
251→        }
252→    }
253→
254→    // -- Simple function: one return value → single-condition mock --
255→
256→    #[test]
257→    fn single_behavior_produces_single_condition() {
258→        let map = make_behavior_map(
259→            "getPrice",
260→            vec![make_behavior(0, vec![json!("widget")], Some(json!(9.99)), None)],
261→        );
262→
263→        let tree = build_mock_from_behavior_map(&map).expect("should produce a tree");
264→
265→        assert_eq!(tree.symbol, "getPrice");
266→        assert_eq!(tree.conditions.len(), 1);
267→        assert_eq!(tree.conditions[0].return_value, json!(9.99));
268→        assert!(tree.conditions[0].error.is_none());
269→        assert_eq!(tree.conditions[0].input_patterns.len(), 1);
270→        assert_eq!(tree.conditions[0].input_patterns[0].arg_index, 0);
271→        assert_eq!(
272→            tree.conditions[0].input_patterns[0].matcher,
273→            PatternMatcher::Eq {
274→                value: json!("widget")
275→            }
276→        );
277→        assert_eq!(tree.default_return, json!(9.99));
278→    }
279→
280→    // -- Branching function: two conditions --
281→
282→    #[test]
283→    fn branching_function_produces_two_conditions() {
284→        let map = make_behavior_map(
285→            "classify",
286→            vec![
287→                make_behavior(0, vec![json!(5)], Some(json!("positive")), None),
288→                make_behavior(1, vec![json!(-3)], Some(json!("negative")), None),
289→            ],
290→        );
291→
292→        let tree = build_mock_from_behavior_map(&map).expect("should produce a tree");
293→
294→        assert_eq!(tree.conditions.len(), 2);
295→        assert_eq!(tree.conditions[0].return_value, json!("positive"));
296→        assert_eq!(tree.conditions[1].return_value, json!("negative"));
297→
298→        // First condition matches input 5
299→        assert!(matches_condition(&[json!(5)], &tree.conditions[0]));
300→        assert!(!matches_condition(&[json!(-3)], &tree.conditions[0]));
301→
302→        // Second condition matches input -3
303→        assert!(matches_condition(&[json!(-3)], &tree.conditions[1]));
304→        assert!(!matches_condition(&[json!(5)], &tree.conditions[1]));
305→
306→        // Default is the last return value
307→        assert_eq!(tree.default_return, json!("negative"));
308→    }
309→
310→    // -- Error-throwing function → mock includes error condition --
311→
312→    #[test]
313→    fn error_throwing_function_includes_error_condition() {
314→        let map = make_behavior_map(
315→            "safeDivide",
316→            vec![
317→                make_behavior(0, vec![json!(10), json!(2)], Some(json!(5)), None),
318→                make_behavior(
319→                    1,
320→                    vec![json!(1), json!(0)],
321→                    None,
322→                    Some(ErrorInfo {
323→                        error_type: "Error".to_string(),
324→                        message: "division by zero".to_string(),
325→                        stack: None, error_category: None }),
326→                ),
327→            ],
328→        );
329→
330→        let tree = build_mock_from_behavior_map(&map).expect("should produce a tree");
331→
332→        assert_eq!(tree.conditions.len(), 2);
333→
334→        // First condition: normal return
335→        assert!(tree.conditions[0].error.is_none());
336→        assert_eq!(tree.conditions[0].return_value, json!(5));
337→
338→        // Second condition: error
339→        assert_eq!(
340→            tree.conditions[1].error.as_deref(),
341→            Some("division by zero")
342→        );
343→
344→        // Default return comes from the last non-error behavior
345→        assert_eq!(tree.default_return, json!(5));
346→    }
347→
348→    // -- Multiple parameters → correct arg_index --
349→
350→    #[test]
351→    fn multiple_parameters_have_correct_arg_indices() {
352→        let map = make_behavior_map(
353→            "add",
354→            vec![make_behavior(
355→                0,
356→                vec![json!(3), json!(4), json!("extra")],
357→                Some(json!(7)),
358→                None,
359→            )],
360→        );
361→
362→        let tree = build_mock_from_behavior_map(&map).expect("should produce a tree");
363→
364→        let patterns = &tree.conditions[0].input_patterns;
365→        assert_eq!(patterns.len(), 3);
366→        assert_eq!(patterns[0].arg_index, 0);
367→        assert_eq!(
368→            patterns[0].matcher,
369→            PatternMatcher::Eq { value: json!(3) }
370→        );
371→        assert_eq!(patterns[1].arg_index, 1);
372→        assert_eq!(
373→            patterns[1].matcher,
374→            PatternMatcher::Eq { value: json!(4) }
375→        );
376→        assert_eq!(patterns[2].arg_index, 2);
377→        assert_eq!(
378→            patterns[2].matcher,
379→            PatternMatcher::Eq {
380→                value: json!("extra")
381→            }
382→        );
383→    }
384→
385→    // -- to_enhanced_mock_config produces valid MockConfig --
386→
387→    #[test]
388→    fn enhanced_mock_config_from_decision_tree() {
389→        let map = make_behavior_map(
390→            "lookup",
391→            vec![
392→                make_behavior(0, vec![json!("a")], Some(json!(1)), None),
393→                make_behavior(1, vec![json!("b")], Some(json!(2)), None),
394→                make_behavior(
395→                    2,
396→                    vec![json!("bad")],
397→                    None,
398→                    Some(ErrorInfo {
399→                        error_type: "Error".to_string(),
400→                        message: "not found".to_string(),
401→                        stack: None, error_category: None }),
402→                ),
403→            ],
404→        );
405→
406→        let tree = build_mock_from_behavior_map(&map).expect("should produce a tree");
407→        let config = to_enhanced_mock_config(&tree);
408→
409→        assert_eq!(config.symbol, "lookup");
410→        // Error conditions are filtered out of return_values
411→        assert_eq!(config.return_values, vec![json!(1), json!(2)]);
412→        assert!(config.should_track_calls);
413→        assert_eq!(config.default_behavior, MockBehavior::RepeatLast);
414→    }
415→
416→    // -- Empty behavior map → None --
417→
418→    #[test]
419→    fn empty_behavior_map_returns_none() {
420→        let map = make_behavior_map("noop", vec![]);
421→        assert!(build_mock_from_behavior_map(&map).is_none());
422→    }
423→
424→    // -- mock_config_from_behavior_map fallback --
425→
426→    #[test]
427→    fn fallback_to_flat_mock_when_no_tree() {
428→        let map = make_behavior_map("noop", vec![]);
429→        let config = mock_config_from_behavior_map(&map);
430→        assert_eq!(config.symbol, "noop");
431→        assert!(config.return_values.is_empty());
432→    }
433→
434→    #[test]
435→    fn mock_config_from_behavior_map_uses_tree_when_possible() {
436→        let map = make_behavior_map(
437→            "fn1",
438→            vec![
439→                make_behavior(0, vec![json!(1)], Some(json!("a")), None),
440→                make_behavior(
441→                    1,
442→                    vec![json!(2)],
443→                    None,
444→                    Some(ErrorInfo {
445→                        error_type: "Error".to_string(),
446→                        message: "fail".to_string(),
447→                        stack: None, error_category: None }),
448→                ),
449→            ],
450→        );
451→
452→        let config = mock_config_from_behavior_map(&map);
453→        // Tree filters out error conditions from return_values
454→        assert_eq!(config.return_values, vec![json!("a")]);
455→    }
456→
457→    // -- Pattern matching tests --
458→
459→    #[test]
460→    fn eq_pattern_matches_exact_value() {
461→        let matcher = PatternMatcher::Eq { value: json!(42) };
462→        assert!(matches_pattern(&json!(42), &matcher));
463→        assert!(!matches_pattern(&json!(43), &matcher));
464→        assert!(!matches_pattern(&json!("42"), &matcher));
465→    }
466→
467→    #[test]
468→    fn range_pattern_matches_inclusive_bounds() {
469→        let matcher = PatternMatcher::Range {
470→            min: 0.0,
471→            max: 10.0,
472→        };
473→        assert!(matches_pattern(&json!(0), &matcher));
474→        assert!(matches_pattern(&json!(5), &matcher));
475→        assert!(matches_pattern(&json!(10), &matcher));
476→        assert!(!matches_pattern(&json!(-1), &matcher));
477→        assert!(!matches_pattern(&json!(11), &matcher));
478→        assert!(!matches_pattern(&json!("five"), &matcher));
479→    }
480→
481→    #[test]
482→    fn type_pattern_matches_json_type() {
483→        let matcher = PatternMatcher::Type {
484→            type_name: "string".to_string(),
485→        };
486→        assert!(matches_pattern(&json!("hello"), &matcher));
487→        assert!(!matches_pattern(&json!(42), &matcher));
488→
489→        let num_matcher = PatternMatcher::Type {
490→            type_name: "number".to_string(),
491→        };
492→        assert!(matches_pattern(&json!(42), &num_matcher));
493→        assert!(!matches_pattern(&json!("42"), &num_matcher));
494→    }
495→
496→    #[test]
497→    fn any_pattern_matches_everything() {
498→        let matcher = PatternMatcher::Any;
499→        assert!(matches_pattern(&json!(null), &matcher));
500→        assert!(matches_pattern(&json!(42), &matcher));
501→        assert!(matches_pattern(&json!("hello"), &matcher));
502→        assert!(matches_pattern(&json!([1, 2, 3]), &matcher));
503→    }
504→
505→    #[test]
506→    fn matches_condition_requires_all_patterns() {
507→        let condition = MockCondition {
508→            input_patterns: vec![
509→                InputPattern {
510→                    arg_index: 0,
511→                    matcher: PatternMatcher::Eq { value: json!(1) },
512→                },
513→                InputPattern {
514→                    arg_index: 1,
515→                    matcher: PatternMatcher::Eq { value: json!(2) },
516→                },
517→            ],
518→            return_value: json!(3),
519→            error: None,
520→        };
521→
522→        assert!(matches_condition(&[json!(1), json!(2)], &condition));
523→        assert!(!matches_condition(&[json!(1), json!(3)], &condition));
524→        assert!(!matches_condition(&[json!(2), json!(2)], &condition));
525→        // Missing argument
526→        assert!(!matches_condition(&[json!(1)], &condition));
527→    }
528→
529→    // -- Serialization round-trip --
530→
531→    #[test]
532→    fn decision_tree_round_trips_through_json() {
533→        let tree = MockDecisionTree {
534→            symbol: "myFunc".to_string(),
535→            conditions: vec![
536→                MockCondition {
537→                    input_patterns: vec![InputPattern {
538→                        arg_index: 0,
539→                        matcher: PatternMatcher::Eq { value: json!(1) },
540→                    }],
541→                    return_value: json!("one"),
542→                    error: None,
543→                },
544→                MockCondition {
545→                    input_patterns: vec![InputPattern {
546→                        arg_index: 0,
547→                        matcher: PatternMatcher::Range {
548→                            min: 2.0,
549→                            max: 10.0,
550→                        },
551→                    }],
552→                    return_value: json!("many"),
553→                    error: None,
554→                },
555→            ],
556→            default_return: json!("unknown"),
557→        };
558→
559→        let json = serde_json::to_string(&tree).expect("serialize");
560→        let deserialized: MockDecisionTree =
561→            serde_json::from_str(&json).expect("deserialize");
562→        assert_eq!(tree, deserialized);
563→    }
564→
565→    // -- Behavior with no return and no error is skipped --
566→
567→    #[test]
568→    fn behavior_without_return_or_error_is_skipped() {
569→        let map = make_behavior_map(
570→            "sideEffectOnly",
571→            vec![
572→                // This behavior has neither return nor error — should be skipped
573→                Behavior {
574→                    id: 0,
575→                    input_args: vec![json!("x")],
576→                    return_value: None,
577→                    thrown_error: None,
578→                    branch_path: vec![],
579→                    side_effects: vec![],
580→                    dependency_trace: None,
581→                    mock_values: vec![],
582→                },
583→                make_behavior(1, vec![json!("y")], Some(json!("ok")), None),
584→            ],
585→        );
586→
587→        let tree = build_mock_from_behavior_map(&map).expect("should produce a tree");
588→        // Only the second behavior produced a condition
589→        assert_eq!(tree.conditions.len(), 1);
590→        assert_eq!(tree.conditions[0].return_value, json!("ok"));
591→    }
592→}
