// ---------------------------------------------------------------------------
// Type-driven error variant generation
// ---------------------------------------------------------------------------

/// Result of error variant generation: either a concrete error value or
/// a signal that the mock should throw.
#[derive(Debug, Clone, PartialEq)]
pub enum ErrorVariant {
    /// A concrete JSON value representing the error case.
    Value(Value),
    /// No meaningful error value can be derived from the type; the mock
    /// should use [`MockBehavior::ThrowError`] instead.
    Throw,
}

/// Generate an error variant value appropriate for the given return type.
///
/// Produces different error shapes depending on the type structure:
/// - **Object with `status` field**: HTTP error object with 400 or 500 status
/// - **Complex Result type**: `{ok: false, value: "mock error"}` tagged format
/// - **Nullable**: `null`
/// - **Union containing Error complex type**: the error variant
/// - **Unknown with category context**: category-aware error shape
/// - **Fallback**: `null` (callers should use `ThrowError` behavior instead)
pub fn generate_error_variant(
    return_type: &TypeInfo,
    category: IoCategory,
    rng: &mut impl Rng,
) -> ErrorVariant {
    match return_type {
        // Object with a "status" field -> HTTP-style error response
        TypeInfo::Object { fields } if has_status_field(fields) => {
            let status = if rng.random_bool(0.5) { 400 } else { 500 };
            let mut obj = serde_json::Map::new();
            for (name, field_type) in fields {
                if name == "status" {
                    obj.insert(name.clone(), json!(status));
                } else if name == "data" || name == "body" {
                    obj.insert(name.clone(), Value::Null);
                } else if name == "error" || name == "message" {
                    obj.insert(name.clone(), json!("mock error"));
                } else {
                    obj.insert(name.clone(), default_for_type(field_type));
                }
            }
            ErrorVariant::Value(Value::Object(obj))
        }

        // Complex Result type -> Err variant in tagged wire format
        TypeInfo::Complex { kind: ComplexKind::Result, .. } => {
            ErrorVariant::Value(
                json!({"__complex_type": "result", "ok": false, "value": "mock error"}),
            )
        }

        // Nullable -> null
        TypeInfo::Nullable { .. } => ErrorVariant::Value(Value::Null),

        // Union containing an Error variant -> pick the error variant
        TypeInfo::Union { variants } => {
            let error_idx = variants.iter().position(|v| {
                matches!(v, TypeInfo::Complex { kind: ComplexKind::Error, .. })
            });
            if let Some(idx) = error_idx {
                let metadata = match &variants[idx] {
                    TypeInfo::Complex { metadata, .. } => metadata.clone(),
                    _ => serde_json::Map::new(),
                };
                let class = metadata
                    .get("class")
                    .and_then(|c| c.as_str())
                    .unwrap_or("Error");
                ErrorVariant::Value(
                    json!({"__complex_type": "error", "class": class, "message": "mock error"}),
                )
            } else {
                // Union without error variant -> ThrowError fallback
                ErrorVariant::Throw
            }
        }

        // Unknown type -> category-aware error shape
        TypeInfo::Unknown => {
            ErrorVariant::Value(category_error_shape(category))
        }

        // Everything else -> ThrowError fallback
        _ => ErrorVariant::Throw,
    }
}

/// Generate error-case [`MockConfig`]s for a set of mock parameters.
///
/// For each mock param, with probability `error_probability`, replaces
/// some return values with error variants derived from the return type.
/// When `error_probability` is 0.0, returns the original configs unchanged.
pub fn generate_error_mock_configs(
    base_configs: &[MockConfig],
    mock_params: &[MockParam],
    error_probability: f64,
    rng: &mut impl Rng,
) -> Vec<MockConfig> {
    base_configs
        .iter()
        .zip(mock_params.iter())
        .map(|(config, mp)| {
            if error_probability <= 0.0 || config.return_values.is_empty() {
                return config.clone();
            }

            let variant = generate_error_variant(&mp.return_type, mp.category, rng);

            match variant {
                ErrorVariant::Throw => {
                    // No type-driven error value possible -- use ThrowError behavior
                    // so the TS executor will throw when return_values are exhausted
                    MockConfig {
                        symbol: config.symbol.clone(),
                        return_values: config.return_values.clone(),
                        should_track_calls: config.should_track_calls,
                        default_behavior: MockBehavior::ThrowError,
                    }
                }
                ErrorVariant::Value(error_val) => {
                    // Inject error values at the configured probability
                    let return_values: Vec<Value> = config
                        .return_values
                        .iter()
                        .map(|v| {
                            if rng.random_range(0.0..1.0_f64) < error_probability {
                                error_val.clone()
                            } else {
                                v.clone()
                            }
                        })
                        .collect();

                    MockConfig {
                        symbol: config.symbol.clone(),
                        return_values,
                        should_track_calls: config.should_track_calls,
                        default_behavior: config.default_behavior.clone(),
                    }
                }
            }
        })
        .collect()
}

/// Whether an object type has a field named "status" (case-insensitive).
fn has_status_field(fields: &[(String, TypeInfo)]) -> bool {
    fields.iter().any(|(name, _)| name.eq_ignore_ascii_case("status"))
}

/// Category-aware error shape for `Unknown` return types.
fn category_error_shape(category: IoCategory) -> Value {
    match category {
        IoCategory::Network => json!({"status": 500, "data": null, "error": "Internal Server Error"}),
        IoCategory::Database => json!({"error": "connection refused", "code": "ECONNREFUSED"}),
        IoCategory::FileSystem => json!({"code": "ENOENT", "message": "no such file or directory"}),
        IoCategory::PureUtility | IoCategory::ExternalOther => Value::Null,
    }
}

